#include <stdio.h>
#include <stdlib.h>

//Structure to hold a node information
struct Node
{
	int starting;
	int no_of_edges;
};

// Kernel 1: Process nodes in the current mask
__global__ void bfs_kernel1(int num_nodes, const Node *d_graph_nodes, const bool *d_graph_mask, const int *d_graph_edges, const bool *d_graph_visited, int *d_cost, bool *d_updating_graph_mask)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;

    if (tid < num_nodes && d_graph_mask[tid] == true) {
        // Mark current node as processed for this iteration
        // Note: This modification is local to the kernel's view of d_graph_mask
        // and will be overwritten by kernel 2 if it's updated.
        // A more robust approach might involve a separate 'processed' flag or
        // careful synchronization if d_graph_mask was to be modified here.
        // For this BFS, the logic relies on kernel 2 to reset the mask for the next iteration.

        for (int i = d_graph_nodes[tid].starting; i < (d_graph_nodes[tid].no_of_edges + d_graph_nodes[tid].starting); i++) {
            int id = d_graph_edges[i];
            if (!d_graph_visited[id]) {
                d_cost[id] = d_cost[tid] + 1;
                d_updating_graph_mask[id] = true;
            }
        }
    }
}

// Kernel 2: Update mask and visited status
__global__ void bfs_kernel2(int num_nodes, const bool *d_updating_graph_mask, bool *d_graph_mask, bool *d_graph_visited, bool *d_stop)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;

    if (tid < num_nodes && d_updating_graph_mask[tid] == true) {
        d_graph_mask[tid] = true;
        d_graph_visited[tid] = true;
        // Atomically set the stop flag to true if any thread finds a new node
        atomicExch(d_stop, true);
        d_updating_graph_mask[tid] = false;
    }
}

